                if d < nd:
                    nd = d
            od = 10**9
            for r in res:
                d = dist((ox, oy), r)
                if d < od:
                    od = d
            on_res = any(nx == rx and ny == ry for rx, ry in res)
            candidates.append(((0 if on_res else 1), nd, -dist((nx, ny), (ox, oy)), dx, dy, nd - od))
        candidates.sort()
        return [candidates[0][3], candidates[0][4]]

    best = (10**9, -1, 0, 0)
    for dx, dy in moves:
        nx, ny = sx + dx, sy + dy
